        (basePath.endsWith(requestEndpoint) || basePath.endsWith(endpointWithSuffix)))
    );
  }

  return false;
}

export function getPreviewEndpoints(providerType?: string, baseUrl?: string): PreviewEndpoint[] {
  const endpoints = providerType
