    return (
      basePath.endsWith(endpoint) ||
      basePath.endsWith(requestRoot) ||
      (suffix.length > 0 &&
        (basePath.endsWith(requestEndpoint) || basePath.endsWith(endpointWithSuffix)))
    );
  }

  return false;
}

