184  */
185 export type ModelOwner = "anthropic" | "openai" | "google" | "deepseek" | "alibaba" | "unknown";
186 
187 /**
188  * 根据模型 ID 推断所有者
189  */
190 export function inferOwner(modelId: string): ModelOwner {
191   if (modelId.startsWith("claude-")) return "anthropic";
192   if (modelId.startsWith("gpt-") || modelId.startsWith("o1") || modelId.startsWith("o3"))
193     return "openai";
194   if (modelId.startsWith("gemini-")) return "google";
195   if (modelId.startsWith("deepseek")) return "deepseek";
196   if (modelId.startsWith("qwen")) return "alibaba";
197   return "unknown";
198 }
