244 /**
245  * 通用模型列表获取函数
246  */
247 async function fetchModelsWithConfig(
248   provider: Provider,
249   config: UpstreamFetchConfig
250 ): Promise<FetchedModel[]> {
251   const baseUrl = provider.url.replace(/\/$/, "");
252   const url = config.buildUrl(baseUrl, provider);
253   const headers = config.buildHeaders(provider);
254   const proxyConfig = createProxyAgentForProvider(provider, url);
255   const timeout = getProviderTimeout(provider);
256 
257   const safeUrl = url.replace(/[?&]key=[^&]+/, "[key=REDACTED]");
258   logger.debug(`[AvailableModels] Fetching models from ${provider.name}: ${safeUrl}`);
259 
260   const response = await undiciRequest(url, {
261     method: "GET",
262     headers,
263     dispatcher: proxyConfig?.agent,
264     headersTimeout: timeout,
265     bodyTimeout: timeout,
266   });
267 
268   if (response.statusCode !== 200) {
269     const errorBody = await response.body.text();
270     logger.debug(
271       `[AvailableModels] ${provider.name} returned ${response.statusCode}: ${errorBody}`
272     );
273     throw new Error(`${provider.name} API returned ${response.statusCode}`);
274   }
275 
276   const body = await response.body.json();
277   const models = config.parseResponse(body);
278 
279   logger.debug(`[AvailableModels] ${provider.name} returned ${models.length} models`);
280   return models;
281 }
