283 /**
284  * 根据 Provider 类型获取模型列表
285  *
286  * 优先级：
287  * 1. 如果 provider 配置了 allowedModels，直接使用（无需查上游）
288  * 2. 否则根据 providerType 查询上游
289  */
290 async function fetchModelsFromProvider(provider: Provider): Promise<FetchedModel[]> {
291   if (provider.allowedModels && provider.allowedModels.length > 0) {
292     logger.debug(`[AvailableModels] Using configured allowedModels for ${provider.name}`, {
293       modelCount: provider.allowedModels.length,
294     });
295     return (normalizeAllowedModelRules(provider.allowedModels) ?? [])
296       .filter((rule) => rule.matchType === "exact")
297       .map((rule) => ({ id: rule.pattern }));
298   }
299 
300   const configMap: Record<Provider["providerType"], UpstreamFetchConfig> = {
301     claude: UPSTREAM_CONFIGS.claude,
302     "claude-auth": UPSTREAM_CONFIGS.claude,
303     "openai-compatible": UPSTREAM_CONFIGS.openai,
304     codex: UPSTREAM_CONFIGS.openai,
305     gemini: UPSTREAM_CONFIGS.gemini,
306     "gemini-cli": UPSTREAM_CONFIGS.gemini,
307   };
308 
309   const config = configMap[provider.providerType];
310   if (!config) {
311     logger.warn(`[AvailableModels] Unknown provider type: ${provider.providerType}`);
312     return [];
313   }
314 
315   try {
316     return await fetchModelsWithConfig(provider, config);
317   } catch (error) {
318     logger.warn(`[AvailableModels] Failed to fetch from ${provider.name}:`, error);
319     return [];
320   }
321 }
