182 /**
183  * 模型所有者类型
184  */
185 export type ModelOwner = "anthropic" | "openai" | "google" | "deepseek" | "alibaba" | "unknown";
186 
187 /**
188  * 根据模型 ID 推断所有者
189  */
190 export function inferOwner(modelId: string): ModelOwner {
191   if (modelId.startsWith("claude-")) return "anthropic";
192   if (modelId.startsWith("gpt-") || modelId.startsWith("o1") || modelId.startsWith("o3"))
193     return "openai";
194   if (modelId.startsWith("gemini-")) return "google";
195   if (modelId.startsWith("deepseek")) return "deepseek";
196   if (modelId.startsWith("qwen")) return "alibaba";
197   return "unknown";
198 }
199 
200 /** 上游 API 请求配置 */
201 interface UpstreamFetchConfig {
202   buildUrl: (baseUrl: string, provider: Provider) => string;
203   buildHeaders: (provider: Provider) => Record<string, string>;
204   parseResponse: (body: unknown) => FetchedModel[];
205 }
206 
207 /** 各 Provider 类型的请求配置 */
208 const UPSTREAM_CONFIGS: Record<string, UpstreamFetchConfig> = {
209   claude: {
210     buildUrl: (baseUrl) => `${baseUrl}/v1/models`,
211     buildHeaders: (p) => ({ "x-api-key": p.key, "anthropic-version": "2023-06-01" }),
212     parseResponse: (body) => {
213       const data =
214         (body as { data?: Array<{ id: string; display_name?: string; created_at?: string }> })
215           .data || [];
216       return data.map((m) => ({ id: m.id, displayName: m.display_name, createdAt: m.created_at }));
217     },
218   },
219   openai: {
220     buildUrl: (baseUrl) => `${baseUrl}/v1/models`,
221     buildHeaders: (p) => ({ Authorization: `Bearer ${p.key}` }),
222     parseResponse: (body) => {
223       const data = (body as { data?: Array<{ id: string }> }).data || [];
224       return data.map((m) => ({ id: m.id }));
225     },
226   },
227   gemini: {
228     buildUrl: (baseUrl) => {
229       const prefix = baseUrl.endsWith("/v1beta") ? baseUrl : `${baseUrl}/v1beta`;
230       return `${prefix}/models`;
231     },
232     buildHeaders: (p) => ({ "x-goog-api-key": p.key }),
233     parseResponse: (body) => {
234       const models =
235         (body as { models?: Array<{ name: string; displayName?: string }> }).models || [];
236       return models.map((m) => ({
237         id: m.name.replace(/^models\//, ""),
238         displayName: m.displayName,
239       }));
240     },
241   },
242 };
243 
244 /**
245  * 通用模型列表获取函数
246  */
247 async function fetchModelsWithConfig(
248   provider: Provider,
249   config: UpstreamFetchConfig
250 ): Promise<FetchedModel[]> {
251   const baseUrl = provider.url.replace(/\/$/, "");
252   const url = config.buildUrl(baseUrl, provider);
253   const headers = config.buildHeaders(provider);
254   const proxyConfig = createProxyAgentForProvider(provider, url);
255   const timeout = getProviderTimeout(provider);
256 
257   const safeUrl = url.replace(/[?&]key=[^&]+/, "[key=REDACTED]");
258   logger.debug(`[AvailableModels] Fetching models from ${provider.name}: ${safeUrl}`);
259 
260   const response = await undiciRequest(url, {
261     method: "GET",
262     headers,
263     dispatcher: proxyConfig?.agent,
264     headersTimeout: timeout,
265     bodyTimeout: timeout,
266   });
267 
268   if (response.statusCode !== 200) {
269     const errorBody = await response.body.text();
270     logger.debug(
271       `[AvailableModels] ${provider.name} returned ${response.statusCode}: ${errorBody}`
272     );
273     throw new Error(`${provider.name} API returned ${response.statusCode}`);
274   }
275 
276   const body = await response.body.json();
277   const models = config.parseResponse(body);
278 
279   logger.debug(`[AvailableModels] ${provider.name} returned ${models.length} models`);
280   return models;
281 }
282 
283 /**
284  * 根据 Provider 类型获取模型列表
285  *
286  * 优先级：
287  * 1. 如果 provider 配置了 allowedModels，直接使用（无需查上游）
288  * 2. 否则根据 providerType 查询上游
289  */
290 async function fetchModelsFromProvider(provider: Provider): Promise<FetchedModel[]> {
291   if (provider.allowedModels && provider.allowedModels.length > 0) {
292     logger.debug(`[AvailableModels] Using configured allowedModels for ${provider.name}`, {
293       modelCount: provider.allowedModels.length,
294     });
295     return (normalizeAllowedModelRules(provider.allowedModels) ?? [])
296       .filter((rule) => rule.matchType === "exact")
297       .map((rule) => ({ id: rule.pattern }));
298   }
299 
300   const configMap: Record<Provider["providerType"], UpstreamFetchConfig> = {
301     claude: UPSTREAM_CONFIGS.claude,
302     "claude-auth": UPSTREAM_CONFIGS.claude,
303     "openai-compatible": UPSTREAM_CONFIGS.openai,
304     codex: UPSTREAM_CONFIGS.openai,
305     gemini: UPSTREAM_CONFIGS.gemini,
306     "gemini-cli": UPSTREAM_CONFIGS.gemini,
307   };
308 
309   const config = configMap[provider.providerType];
310   if (!config) {
311     logger.warn(`[AvailableModels] Unknown provider type: ${provider.providerType}`);
312     return [];
313   }
314 
315   try {
316     return await fetchModelsWithConfig(provider, config);
317   } catch (error) {
318     logger.warn(`[AvailableModels] Failed to fetch from ${provider.name}:`, error);
319     return [];
320   }
321 }
