323 /**
324  * 根据客户端格式获取需要决策的 providerType 列表
325  */
326 export function getProviderTypesForFormat(clientFormat: ClientFormat): Provider["providerType"][] {
327   switch (clientFormat) {
328     case "claude":
329       return ["claude", "claude-auth"];
330     case "openai":
331       // openai 格式需要对 codex 和 openai-compatible 分别决策
332       return ["codex", "openai-compatible"];
333     case "gemini":
334     case "gemini-cli":
335       return ["gemini", "gemini-cli"];
336     case "response":
337       return ["codex"];
338     default: {
339       const _exhaustiveCheck: never = clientFormat;
340       throw new Error(`Unknown client format: ${_exhaustiveCheck}`);
341     }
342   }
343 }
344 
345 /**
346  * 获取用户可用的模型列表
347  *
348  * 决策流程：
349  * 1. 根据 clientFormat 确定需要决策的 providerType 列表
