385 /**
386  * 将时间戳归一化为 Anthropic API 规范格式(秒级精度,不含毫秒)。
387  *
388  * 官方 Anthropic /v1/models 的 created_at 形如 `2026-05-29T09:22:44Z`,不含毫秒;
389  * 而 Date.toISOString() 始终输出 `.SSSZ`,部分上游也会带毫秒,因此统一去除。
390  * 无法解析的上游时间戳原样返回,避免抛错。
391  */
392 function normalizeAnthropicTimestamp(value: string): string {
393   const parsed = new Date(value);
394   if (Number.isNaN(parsed.getTime())) {
395     return value;
396   }
397   return parsed.toISOString().replace(/\.\d{3}Z$/, "Z");
398 }
399 
400 /**
401  * 格式化为 Anthropic 响应
402  */
403 export function formatAnthropicResponse(models: FetchedModel[]): AnthropicModelsResponse {
404   const now = normalizeAnthropicTimestamp(new Date().toISOString());
405   const data = models.map((m) => ({
406     id: m.id,
407     type: "model" as const,
408     display_name: m.displayName || m.id,
409     created_at: m.createdAt ? normalizeAnthropicTimestamp(m.createdAt) : now,
410   }));
411 
412   return { data, has_more: false };
413 }
414 
415 /**
416  * 格式化为 Gemini 响应
417  */
418 export function formatGeminiResponse(models: FetchedModel[]): GeminiModelsResponse {
419   const geminiModels = models.map((m) => ({
420     name: `models/${m.id}`,
421     displayName: m.displayName || m.id,
422     supportedGenerationMethods: ["generateContent"],
423   }));
424 
425   return { models: geminiModels };
426 }
