428 /**
429  * 根据指定的 providerTypes 获取模型列表
430  *
431  * 与代理请求不同，模型列表需要展示所有已启用 provider 的模型（不做健康检查），
432  * 因为模型列表的职责是"告诉用户有哪些模型可用"，实时可用性由代理请求时的守卫链处理。
433  *
434  * Fix: #956 — 之前复用 selectProviderByType() 导致每种类型只选 1 个 provider
435  */
436 async function getAvailableModelsByProviderTypes(
437   authState: {
438     user: { id: number; providerGroup: string | null };
439     key: { providerGroup: string | null };
440   },
441   providerTypes: Provider["providerType"][]
442 ): Promise<{ models: FetchedModel[]; providerName?: string }> {
443   const allProviders = await findAllProviders();
444 
445   // 过滤出所有匹配的供应商
446   const effectiveGroup = authState.key.providerGroup || authState.user.providerGroup || null;
447   const providerTypeSet = new Set(providerTypes);
448   const systemTimezone = await resolveSystemTimezone();
449 
450   const matchedProviders = allProviders.filter(
451     (p) =>
452       p.isEnabled &&
453       providerTypeSet.has(p.providerType) &&
454       isProviderActiveNow(p.activeTimeStart, p.activeTimeEnd, systemTimezone) &&
455       (!effectiveGroup || checkProviderGroupMatch(p.groupTag, effectiveGroup))
456   );
457 
458   if (matchedProviders.length === 0) {
459     logger.warn("[AvailableModels] No available provider", {
460       userId: authState.user.id,
461       triedTypes: providerTypes,
462     });
463     return { models: [] };
464   }
465 
466   logger.debug("[AvailableModels] Matched providers for models list", {
467     providerTypes,
468     providerCount: matchedProviders.length,
469     providers: matchedProviders.map((p) => ({ id: p.id, name: p.name, type: p.providerType })),
470   });
471 
472   const allModels: FetchedModel[] = [];
473   const seenIds = new Set<string>();
474 
475   const fetchResults = await Promise.all(
476     matchedProviders.map((provider) => fetchModelsFromProvider(provider))
477   );
478 
479   for (const models of fetchResults) {
480     for (const model of models) {
481       if (!seenIds.has(model.id)) {
482         seenIds.add(model.id);
483         allModels.push(model);
484       }
485     }
486   }
487 
488   logger.info("[AvailableModels] Aggregated models", {
489     userId: authState.user.id,
490     modelCount: allModels.length,

