 70 export function resolveAnthropicAuthHeaders(
 71   apiKey: string,
 72   providerUrl?: string | null,
 73   options?: { forceBearerOnly?: boolean }
 74 ): Record<string, string> {
 75   // AWS External Anthropic 拒绝 Authorization+x-api-key 共存,且不接受 Bearer。
 76   // 上游硬约束优先级最高,即使调用方要求 forceBearerOnly 也按 x-api-key 单发。
 77   if (looksLikeAwsExternalAnthropicUrl(providerUrl)) {
 78     if (options?.forceBearerOnly) {
 79       // 只记录 host：userinfo / query / fragment 都可能携带签名 token 或 API key，
 80       // 直接落整段 URL（甚至仅做 userinfo 脱敏）都会留出泄露面。
 81       logger.warn(
 82         "[anthropic-auth] forceBearerOnly overridden for AWS External Anthropic gateway; sending x-api-key only",
 83         { providerHost: safeUrlHost(providerUrl) }
 84       );
 85     }
 86     return {
 87       "x-api-key": apiKey,
 88     };
 89   }
 90 
 91   if (options?.forceBearerOnly || looksLikeAnthropicProxyUrl(providerUrl)) {
 92     return {
 93       Authorization: `Bearer ${apiKey}`,
 94     };
 95   }
 96 
 97   return {
 98     Authorization: `Bearer ${apiKey}`,
 99     "x-api-key": apiKey,
100   };

