 63     // 避免 `aws-external-anthropic.fake.api.aws` 之类伪造主机伪装成网关。
 64     return /^aws-external-anthropic\.[a-z]+(?:-[a-z]+)+-\d+\.api\.aws$/.test(hostname);
 65   } catch {
 66     return false;
 67   }
 68 }
