 95  * 构建代理目标 URL，并在以下场景下避免重复拼接：
 96  *
 97  * 1. `baseUrl` 已经是完整 endpoint 或 endpoint 根路径
 98  * 2. `baseUrl` 只停在版本根路径，例如 `/v1`、`/v4`、`/v1beta`
 99  * 3. `requestUrl` 命中的是 endpoint 子路径，例如 `/v1/messages/count_tokens`
100  *
101  * @param baseUrl - 基础URL（用户配置的供应商URL）
102  *   - 示例 1：`https://api.openai.com` -> 需要拼接
103  *   - 示例 2：`https://xxx.com/openai/responses` -> 已包含完整 endpoint
104  *   - 示例 3：`https://xxx.com/openai/v1` -> 只包含版本根路径
105  * @param requestUrl - 原始请求URL对象（包含路径和查询参数）
106  * @returns 拼接后的完整URL字符串
107  */
108 export function buildProxyUrl(baseUrl: string, requestUrl: URL): string {
109   try {
110     // 解析baseUrl
111     const baseUrlObj = new URL(baseUrl);
112     const basePath = baseUrlObj.pathname.replace(/\/$/, ""); // 移除末尾斜杠
113     const requestPath = requestUrl.pathname; // 原始请求路径（如 /v1/messages）
114 
115     // Case 1: baseUrl 已是 requestPath 的前缀（例如 base=/v1/messages, req=/v1/messages/count_tokens）
116     // 直接使用 requestPath，避免丢失子路径。
117     if (requestPath === basePath || requestPath.startsWith(`${basePath}/`)) {
118       baseUrlObj.pathname = requestPath;
119       baseUrlObj.search = requestUrl.search;
120       return baseUrlObj.toString();
121     }
122 
123     // Case 2: baseUrl 已包含“端点根路径”（可能带有额外前缀），仅追加 requestPath 的子路径部分。
124 
125     for (const { endpoint, regex } of endpointRegexes) {
126       const endpointMatch = requestPath.match(regex);
127       if (!endpointMatch) continue;
128 
129       const versionPrefix = endpointMatch[1];
130       const requestRoot = `/${versionPrefix}${endpoint}`;
131       const suffix = endpointMatch.groups?.suffix ?? "";
132       const requestEndpoint = `${requestRoot}${suffix}`;
133       const endpointWithSuffix = `${endpoint}${suffix}`;
134       const hasFullEndpoint =
135         suffix.length > 0 &&
136         (basePath.endsWith(requestEndpoint) || basePath.endsWith(endpointWithSuffix));
137 
138       if (hasFullEndpoint || basePath.endsWith(endpoint) || basePath.endsWith(requestRoot)) {
139         baseUrlObj.pathname = hasFullEndpoint ? basePath : basePath + suffix;
140         baseUrlObj.search = requestUrl.search;
141 
142         logger.debug("[buildProxyUrl] Detected endpoint root in baseUrl", {
143           basePath,
144           requestPath,
145           endpoint,
146           action: hasFullEndpoint ? "reuse_full_endpoint" : "append_suffix",
147         });
148 
149         return baseUrlObj.toString();
150       }
151 
152       if (isVersionRootPath(basePath)) {
153         baseUrlObj.pathname = `${basePath}${endpoint}${suffix}`;
154         baseUrlObj.search = requestUrl.search;
155 
156         logger.debug("[buildProxyUrl] Detected version root in baseUrl", {
157           basePath,
158           requestPath,
159           endpoint,
160           action: "append_endpoint",
161         });
162 
163         return baseUrlObj.toString();
164       }
165     }

