 3   AllowedModelRule,
 4   AllowedModelRuleInput,
 5   ProviderModelRedirectMatchType,
 6 } from "@/types/provider";
 7 
 8 const ALLOWED_MODEL_MATCH_TYPES = new Set<ProviderModelRedirectMatchType>([
 9   "exact",
10   "prefix",
11   "suffix",
12   "contains",
13   "regex",
14 ]);
15 
16 function isRecord(value: unknown): value is Record<string, unknown> {
17   return typeof value === "object" && value !== null && !Array.isArray(value);
18 }
19 
20 function trimString(value: unknown): string | null {
21   return typeof value === "string" ? value.trim() : null;
22 }
23 
24 export function isAllowedModelRule(value: unknown): value is AllowedModelRule {
25   if (!isRecord(value)) {
26     return false;
27   }
28 
29   const matchType = value.matchType;
30   const pattern = trimString(value.pattern);
31 
32   return (
33     typeof matchType === "string" &&
34     ALLOWED_MODEL_MATCH_TYPES.has(matchType as ProviderModelRedirectMatchType) &&
35     !!pattern
36   );
37 }
38 
39 export function normalizeAllowedModelRule(value: AllowedModelRuleInput): AllowedModelRule | null {
40   if (typeof value === "string") {
41     const pattern = value.trim();
42     if (!pattern) {
43       return null;
44     }
45     return {
46       matchType: "exact",
47       pattern,
48     };
49   }
